// OpenCL kernel for likelihood calculation and position updates

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

// Helper function for random number generation
double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

// Helper function for normal random distribution
double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

// Helper function for rounding
double roundDouble(double value) {
    int newValue = (int)(value);
    if(value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

// Kernel for updating particle positions with noise
__kernel void position_update_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global int * seed,
    int Nparticles,
    int k)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        arrayX[x] += 1 + 5 * randn(seed, x);
        arrayY[x] += -2 + 2 * randn(seed, x);
    }
}

// Kernel for calculating likelihood for each particle
__kernel void likelihood_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global int * ind,
    __global int * objxy,
    __global double * likelihood,
    __global unsigned char * I,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        int indX, indY;
        double likelihoodSum = 0.0;

        for(int y = 0; y < countOnes; y++) {
            indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
            indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
            int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
            if(idx >= max_size)
                idx = 0;
            ind[x * countOnes + y] = idx;

            likelihoodSum += (pow((I[idx] - 100), 2) - pow((I[idx] - 228), 2)) / 50.0;
        }
        likelihood[x] = likelihoodSum / ((double)countOnes);
    }
}

// Kernel for exponential weight update
__kernel void exponential_kernel(
    __global double * weights,
    __global double * likelihood,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        weights[x] = weights[x] * exp(likelihood[x]);
    }
}

