// OpenCL kernel for weight sum and normalization

// Kernel for summing weights (partial sums for reduction)
__kernel void sum_kernel(
    __global double * weights,
    __global double * partial_sums,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        partial_sums[x] = weights[x];
    }
    // Handle the last element for total sum
    if(x == 0) {
        double sumWeights = 0;
        for(int i = 0; i < Nparticles; i++) {
            sumWeights += weights[i];
        }
        partial_sums[Nparticles] = sumWeights;
    }
}

// Kernel for normalizing weights
__kernel void normalize_weights_kernel(
    __global double * weights,
    __global double * partial_sums,
    __global double * CDF,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        double sumWeights = partial_sums[Nparticles];
        weights[x] = weights[x] / sumWeights;

        if(x == 0) {
            CDF[x] = weights[x];
        } else {
            CDF[x] = weights[x] + CDF[x - 1];
        }
    }
}

// Kernel for calculating weighted position (xe, ye)
__kernel void weighted_position_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global double * weights,
    __global double * xe_ye,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x == 0) {
        double xe = 0;
        double ye = 0;
        for(int i = 0; i < Nparticles; i++) {
            xe += arrayX[i] * weights[i];
            ye += arrayY[i] * weights[i];
        }
        xe_ye[0] = xe;
        xe_ye[1] = ye;
    }
}

