// OpenCL kernel for CDF calculation and particle resampling

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

// Helper function for random number generation
double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

// Helper function for finding index in CDF
int findIndex(__global double * CDF, int lengthCDF, double value) {
    int index = -1;
    for(int x = 0; x < lengthCDF; x++) {
        if(CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if(index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

// Kernel for calculating U values
__kernel void calculate_u_kernel(
    __global double * u,
    __global int * seed,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x == 0) {
        double u1 = (1.0 / ((double)Nparticles)) * randu(seed, 0);
        for(int i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double)Nparticles);
        }
    }
}

// Kernel for finding index and resampling particles
__kernel void find_index_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global double * CDF,
    __global double * u,
    __global double * xj,
    __global double * yj,
    __global double * weights,
    int Nparticles)
{
    int j = get_global_id(0);
    if(j < Nparticles) {
        int i = findIndex(CDF, Nparticles, u[j]);
        if(i == -1)
            i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];

        // Update arrayX and arrayY with resampled values
        arrayX[j] = xj[j];
        arrayY[j] = yj[j];
        weights[j] = 1.0 / ((double)Nparticles);
    }
}

// Kernel for resetting weights
__kernel void reset_weights_kernel(
    __global double * weights,
    int Nparticles)
{
    int x = get_global_id(0);
    if(x < Nparticles) {
        weights[x] = 1.0 / ((double)Nparticles);
    }
}
